        SearchBar: lipgloss.NewStyle().
            Border(lipgloss.RoundedBorder()).
            BorderForeground(colorFoam).
            Padding(0, 1).
            MarginBottom(1),
        Button: lipgloss.NewStyle().
            Foreground(colorSubtle),
        FocusedButton: lipgloss.NewStyle().
            Background(colorIris).
            Foreground(colorBase),
    }
}
